-- Mariner service inventory, certificate facts, and captured
-- curl/httpie probe evidence. Loaded into H2 at image build time.

DROP TABLE IF EXISTS probes;
DROP TABLE IF EXISTS certificates;
DROP TABLE IF EXISTS services;

CREATE TABLE services (
    service_id   VARCHAR(16) PRIMARY KEY,
    name         VARCHAR(64)  NOT NULL,
    environment  VARCHAR(16)  NOT NULL,
    owner        VARCHAR(64)  NOT NULL,
    endpoint     VARCHAR(160) NOT NULL
);

CREATE TABLE certificates (
    service_id   VARCHAR(16) PRIMARY KEY,
    fingerprint  VARCHAR(128) NOT NULL,
    not_after    DATE         NOT NULL,
    key_algo     VARCHAR(8)   NOT NULL,
    key_bits     INT          NOT NULL,
    issuer       VARCHAR(64)  NOT NULL,
    CONSTRAINT fk_cert_service FOREIGN KEY (service_id) REFERENCES services(service_id)
);

CREATE TABLE probes (
    probe_id             INT AUTO_INCREMENT PRIMARY KEY,
    service_id           VARCHAR(16)  NOT NULL,
    tool                 VARCHAR(16)  NOT NULL,
    tls_version          VARCHAR(8)   NOT NULL,
    verify_ok            BOOLEAN      NOT NULL,
    mtls_required        BOOLEAN      NOT NULL,
    mtls_presented       BOOLEAN      NOT NULL,
    chain_valid          BOOLEAN      NOT NULL,
    http_status          INT          NOT NULL,
    observed_fingerprint VARCHAR(128) NOT NULL,
    captured_at          TIMESTAMP    NOT NULL,
    CONSTRAINT fk_probe_service FOREIGN KEY (service_id) REFERENCES services(service_id)
);




